"""The vending machine and its State pattern.

The machine holds inventory but does NOT decide what's legal — it delegates to
its current state object. That's the State pattern: behavior changes with state,
without a big if/else ladder.
"""
from __future__ import annotations

from enum import Enum

from models import InvalidStateTransition, OutOfStockError


class MachineStateType(Enum):
    IDLE = "IDLE"
    OUT_OF_STOCK = "OUT_OF_STOCK"
    MAINTENANCE = "MAINTENANCE"


class MachineState:
    # ── WHY THIS CLASS ──
    # The abstract state. Every concrete state answers the same four questions:
    # can I dispense? restock? enter maintenance? leave maintenance? The default
    # is "no" — each concrete state opens up only what's legal for it.
    # 🎙️ "Instead of checking the machine's mode everywhere, each mode is its own
    #     class and the machine just forwards the call."
    name: MachineStateType

    def dispense(self, machine: "VendingMachine", item: str) -> None:
        raise InvalidStateTransition(f"cannot dispense in {self.name.value}")

    def restock(self, machine: "VendingMachine", item: str, qty: int) -> None:
        raise InvalidStateTransition(f"cannot restock in {self.name.value}")

    def start_maintenance(self, machine: "VendingMachine") -> None:
        raise InvalidStateTransition(f"cannot start maintenance in {self.name.value}")

    def end_maintenance(self, machine: "VendingMachine") -> None:
        raise InvalidStateTransition(f"not in maintenance ({self.name.value})")


class IdleState(MachineState):
    name = MachineStateType.IDLE

    def dispense(self, machine: "VendingMachine", item: str) -> None:
        # WHY: validate the specific item first — a machine can be Idle overall
        #      but out of ONE item.
        if machine.stock.get(item, 0) <= 0:
            raise OutOfStockError(f"{item} unavailable")
        machine.stock[item] -= 1
        machine.dispense_count += 1
        machine.revenue_cents += machine.price_cents.get(item, 0)
        # WHY: if that was the last item of anything in the machine, flip to
        #      OutOfStock. The state object mutates the machine — service stays dumb.
        # ⚠️ FOLLOW-UP: "What counts as out of stock?"
        #    → "Here, total stock zero. Could refine to per-slot, but the seam
        #       is the same — the state decides and flips itself."
        if sum(machine.stock.values()) == 0:
            machine.set_state(OutOfStockState())

    def restock(self, machine: "VendingMachine", item: str, qty: int) -> None:
        machine.stock[item] = machine.stock.get(item, 0) + qty

    def start_maintenance(self, machine: "VendingMachine") -> None:
        machine.set_state(MaintenanceState())


class OutOfStockState(MachineState):
    name = MachineStateType.OUT_OF_STOCK

    def restock(self, machine: "VendingMachine", item: str, qty: int) -> None:
        machine.stock[item] = machine.stock.get(item, 0) + qty
        # WHY: any restock brings the machine back to life.
        machine.set_state(IdleState())

    def start_maintenance(self, machine: "VendingMachine") -> None:
        machine.set_state(MaintenanceState())


class MaintenanceState(MachineState):
    name = MachineStateType.MAINTENANCE

    def end_maintenance(self, machine: "VendingMachine") -> None:
        # WHY: leaving maintenance returns to the RIGHT state — Idle if there's
        #      stock, OutOfStock if empty. We don't blindly go to Idle.
        if sum(machine.stock.values()) > 0:
            machine.set_state(IdleState())
        else:
            machine.set_state(OutOfStockState())


class VendingMachine:
    # ── WHY THIS CLASS ──
    # Holds inventory, pricing, and usage counters. Every behavioral call is
    # forwarded to the current state. revenue_cents is what revenue-share billing
    # reads — that's why it lives here, on the machine.
    def __init__(self, id: str, price_cents: dict[str, int],
                 stock: dict[str, int] | None = None) -> None:
        self.id = id
        self.price_cents = dict(price_cents)
        self.stock = dict(stock or {})
        self.dispense_count = 0
        self.revenue_cents = 0
        # WHY: start Idle only if there's something to sell.
        self._state: MachineState = (
            IdleState() if sum(self.stock.values()) > 0 else OutOfStockState()
        )

    @property
    def state(self) -> MachineStateType:
        return self._state.name

    def set_state(self, state: MachineState) -> None:
        self._state = state

    # The machine just forwards — the state decides legality.
    def dispense(self, item: str) -> None:
        self._state.dispense(self, item)

    def restock(self, item: str, qty: int) -> None:
        self._state.restock(self, item, qty)

    def start_maintenance(self) -> None:
        self._state.start_maintenance(self)

    def end_maintenance(self) -> None:
        self._state.end_maintenance(self)

"""The two Strategy families + the external gateway interface.

This file IS the extensibility seam. A new billing type or payment method is a
new class here — LeasingService never changes.
"""
from __future__ import annotations

from abc import ABC, abstractmethod
from typing import TYPE_CHECKING

from machine import VendingMachine
from models import Lessee, PaymentDeclined

if TYPE_CHECKING:
    from models import LeaseAgreement


# ── EXTERNAL GATEWAY (Dependency Inversion) ─────────────────────────────────
class PaymentGateway(ABC):
    # ── WHY THIS CLASS ──
    # The boundary to a real payment vendor. The service depends on THIS, not on
    # Stripe/Adyen — so tests inject a fake.
    # 🎙️ "I extract the gateway as an interface so I can swap in a fake that
    #     fails on demand and test the retry path without real money."
    @abstractmethod
    def charge(self, account_ref: str, amount_cents: int) -> bool:
        """Return True if the charge succeeded."""


# ── BILLING STRATEGY: how MUCH to charge ────────────────────────────────────
class BillingStrategy(ABC):
    @abstractmethod
    def compute_charge(self, machine: VendingMachine, lease: "LeaseAgreement") -> int:
        """Charge in cents for the current billing run."""


class FixedMonthlyBilling(BillingStrategy):
    def __init__(self, rate_cents: int) -> None:
        self.rate_cents = rate_cents

    def compute_charge(self, machine: VendingMachine, lease: "LeaseAgreement") -> int:
        # WHY: flat fee, ignores usage entirely.
        return self.rate_cents


class RevenueShareBilling(BillingStrategy):
    def __init__(self, share_pct: int) -> None:
        self.share_pct = share_pct

    def compute_charge(self, machine: VendingMachine, lease: "LeaseAgreement") -> int:
        # WHY: charge a % of NEW sales only — total revenue minus what we already
        #      billed up to (the checkpoint). Integer math, no float money.
        delta = machine.revenue_cents - lease.last_billed_revenue_cents
        return delta * self.share_pct // 100


# ── PAYMENT STRATEGY: how to COLLECT the money ──────────────────────────────
class PaymentStrategy(ABC):
    @abstractmethod
    def collect(self, amount_cents: int, lessee: Lessee, gateway: PaymentGateway) -> None:
        """Collect the money or raise PaymentDeclined."""


class CreditCardPayment(PaymentStrategy):
    def __init__(self, card_token: str) -> None:
        self.card_token = card_token

    def collect(self, amount_cents, lessee, gateway) -> None:
        if not gateway.charge(self.card_token, amount_cents):
            raise PaymentDeclined("card declined")


class BankTransferPayment(PaymentStrategy):
    def __init__(self, account_no: str) -> None:
        self.account_no = account_no

    def collect(self, amount_cents, lessee, gateway) -> None:
        if not gateway.charge(self.account_no, amount_cents):
            raise PaymentDeclined("ACH failed")


class WalletPayment(PaymentStrategy):
    def collect(self, amount_cents, lessee, gateway) -> None:
        # WHY: wallet is internal — no gateway. Check funds, then deduct.
        if lessee.wallet_balance_cents < amount_cents:
            raise PaymentDeclined("insufficient wallet balance")
        lessee.wallet_balance_cents -= amount_cents

